const config = {
    "previewFeatures": [],
    "clientVersion": "7.6.0",
    "engineVersion": "75cbdc1eb7150937890ad5465d861175c6624711",
    "activeProvider": "postgresql",
    "inlineSchema": "// ============================================================================\n// OnyxLegal — Database Schema\n// AI-Powered Contract & Compliance Operating System\n// ============================================================================\n\ngenerator client {\n  provider = \"prisma-client\"\n  output   = \"../generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// ============================================================================\n// ENUMS\n// ============================================================================\n\nenum UserRole {\n  OWNER\n  ADMIN\n  MEMBER\n  VIEWER\n}\n\nenum Plan {\n  FREE\n  STARTER // ₹999/mo\n  GROWTH // ₹2499/mo\n  BUSINESS // ₹4999/mo\n}\n\nenum ContractStatus {\n  DRAFT\n  IN_REVIEW\n  SENT\n  SIGNED\n  ACTIVE\n  EXPIRED\n  TERMINATED\n}\n\nenum RiskLevel {\n  SAFE\n  LOW\n  MEDIUM\n  HIGH\n  CRITICAL\n}\n\nenum ClauseType {\n  PAYMENT_TERMS\n  LIABILITY\n  INDEMNIFICATION\n  IP_OWNERSHIP\n  CONFIDENTIALITY\n  TERMINATION\n  NON_COMPETE\n  NON_SOLICITATION\n  GOVERNING_LAW\n  DISPUTE_RESOLUTION\n  DATA_PROTECTION\n  FORCE_MAJEURE\n  AUTO_RENEWAL\n  WARRANTY\n  OTHER\n}\n\nenum AnalysisStatus {\n  QUEUED\n  PROCESSING\n  COMPLETED\n  FAILED\n}\n\nenum AnalysisType {\n  QUICK_SCAN // Stage 1: clause extraction\n  RISK_DETECTION // Stage 2: risk scoring\n  DEEP_ANALYSIS // Stage 3: legal reasoning (GPT-4o)\n  FIX_GENERATION // Stage 4: suggested fixes\n}\n\nenum NotificationType {\n  RISK_ALERT\n  SIGNATURE_PENDING\n  CONTRACT_EXPIRING\n  AI_FIX_READY\n  ANALYSIS_COMPLETE\n  SYSTEM\n}\n\nenum TemplateCategory {\n  NDA\n  VENDOR_AGREEMENT\n  EMPLOYMENT_OFFER\n  SERVICE_AGREEMENT\n  CONSULTING\n  FREELANCER\n  PARTNERSHIP\n  CUSTOM\n}\n\n// ============================================================================\n// CORE MODELS\n// ============================================================================\n\n/// Organization — multi-tenancy root\nmodel Tenant {\n  id     String  @id @default(cuid())\n  name   String\n  plan   Plan    @default(FREE)\n  domain String? @unique // e.g. \"acme.com\" for SSO future\n\n  // AI token budget control\n  aiTokensUsed Int @default(0) // tokens consumed this billing cycle\n  aiTokenLimit Int @default(5000) // limit per billing cycle\n\n  billingCycleStart DateTime @default(now())\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Relations\n  users     User[]\n  contracts Contract[]\n  templates Template[] // custom templates only\n\n  @@map(\"tenants\")\n}\n\n/// User — authenticated individual\nmodel User {\n  id         String   @id @default(cuid())\n  supabaseId String   @unique // links to Supabase Auth user\n  tenantId   String\n  email      String\n  name       String?\n  avatarUrl  String?\n  role       UserRole @default(MEMBER)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Relations\n  tenant        Tenant         @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  contracts     Contract[]     @relation(\"CreatedBy\")\n  notifications Notification[]\n\n  @@unique([tenantId, email])\n  @@index([supabaseId])\n  @@map(\"users\")\n}\n\n// ============================================================================\n// CONTRACT SYSTEM\n// ============================================================================\n\n/// Template — system or custom contract templates\nmodel Template {\n  id          String           @id @default(cuid())\n  tenantId    String? // null = system template (available to all)\n  category    TemplateCategory\n  name        String\n  description String?\n  riskScore   Int              @default(95) // AI-assessed template safety score\n\n  // Structured clause blocks (JSON array of clause definitions)\n  clauseBlocks Json @default(\"[]\")\n\n  // Template metadata\n  isSystem    Boolean @default(false)\n  usageCount  Int     @default(0)\n  socialProof String? // \"Used by 850+ B2B SaaS startups\"\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Relations\n  tenant    Tenant?    @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  contracts Contract[]\n\n  @@index([category])\n  @@index([isSystem])\n  @@map(\"templates\")\n}\n\n/// Contract — the core business entity\nmodel Contract {\n  id          String  @id @default(cuid())\n  tenantId    String\n  templateId  String?\n  createdById String\n\n  title     String\n  status    ContractStatus @default(DRAFT)\n  riskScore Int? // 0-100, calculated by AI\n\n  // Parties involved\n  parties Json @default(\"[]\") // [{name, email, role: \"client\"|\"vendor\"|\"employee\"}]\n\n  // Full contract content (rich text / HTML)\n  content String? @db.Text\n\n  // Financial metadata (calculated by AI)\n  contractValue Decimal? @db.Decimal(12, 2)\n  currency      String   @default(\"INR\")\n  monthlyImpact Decimal? @db.Decimal(12, 2) // ₹ risk per month\n\n  // Lifecycle dates\n  effectiveDate  DateTime?\n  expirationDate DateTime?\n  signedAt       DateTime?\n  lastReviewedAt DateTime?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Relations\n  tenant    Tenant            @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  template  Template?         @relation(fields: [templateId], references: [id], onDelete: SetNull)\n  createdBy User              @relation(\"CreatedBy\", fields: [createdById], references: [id])\n  versions  ContractVersion[]\n  clauses   Clause[]\n  analyses  AIAnalysis[]\n\n  @@index([tenantId, status])\n  @@index([tenantId, createdAt(sort: Desc)])\n  @@map(\"contracts\")\n}\n\n/// ContractVersion — immutable version history\nmodel ContractVersion {\n  id         String  @id @default(cuid())\n  contractId String\n  version    Int // 1, 2, 3...\n  content    String  @db.Text\n  changeNote String?\n  changedBy  String // userId\n\n  createdAt DateTime @default(now())\n\n  // Relations\n  contract Contract @relation(fields: [contractId], references: [id], onDelete: Cascade)\n\n  @@unique([contractId, version])\n  @@map(\"contract_versions\")\n}\n\n// ============================================================================\n// AI ANALYSIS SYSTEM\n// ============================================================================\n\n/// Clause — individual clause extracted from a contract\nmodel Clause {\n  id         String     @id @default(cuid())\n  contractId String\n  type       ClauseType\n  section    String? // e.g. \"Section 4.2\"\n\n  originalText  String    @db.Text\n  suggestedText String?   @db.Text // AI-suggested improvement\n  riskLevel     RiskLevel @default(SAFE)\n  riskReason    String? // Human-readable risk explanation\n\n  // Financial impact of this clause\n  estimatedImpact Decimal? @db.Decimal(12, 2)\n  impactPeriod    String? // \"monthly\", \"annually\", \"one-time\"\n\n  isAccepted Boolean @default(false) // user accepted AI suggestion\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Relations\n  contract Contract @relation(fields: [contractId], references: [id], onDelete: Cascade)\n\n  @@index([contractId])\n  @@index([riskLevel])\n  @@map(\"clauses\")\n}\n\n/// AIAnalysis — async AI job tracking\nmodel AIAnalysis {\n  id         String         @id @default(cuid())\n  contractId String\n  type       AnalysisType\n  status     AnalysisStatus @default(QUEUED)\n\n  // Cost tracking\n  tokensUsed   Int     @default(0)\n  modelUsed    String? // \"gpt-4o-mini\" or \"gpt-4o\"\n  processingMs Int? // execution time in ms\n\n  // Error handling\n  errorMessage String?\n  retryCount   Int     @default(0)\n\n  startedAt   DateTime?\n  completedAt DateTime?\n  createdAt   DateTime  @default(now())\n\n  // Relations\n  contract     Contract      @relation(fields: [contractId], references: [id], onDelete: Cascade)\n  riskFindings RiskFinding[]\n\n  @@index([contractId, type])\n  @@index([status])\n  @@map(\"ai_analyses\")\n}\n\n/// RiskFinding — individual risk item from AI analysis\nmodel RiskFinding {\n  id         String    @id @default(cuid())\n  analysisId String\n  severity   RiskLevel\n  title      String // \"Uncapped Liability\"\n  clause     String    @db.Text // the problematic clause text\n  impact     String // \"Exposes company to unlimited financial liability\"\n  suggestion String    @db.Text // AI-suggested fix\n  legalRef   String? // \"Indian Contract Act, Section 27\"\n\n  // Financial impact\n  estimatedRisk Decimal? @db.Decimal(12, 2)\n\n  createdAt DateTime @default(now())\n\n  // Relations\n  analysis AIAnalysis @relation(fields: [analysisId], references: [id], onDelete: Cascade)\n\n  @@index([analysisId])\n  @@map(\"risk_findings\")\n}\n\n// ============================================================================\n// NOTIFICATIONS\n// ============================================================================\n\n/// Notification — in-app alerts\nmodel Notification {\n  id     String           @id @default(cuid())\n  userId String\n  type   NotificationType\n  title  String\n  body   String\n  read   Boolean          @default(false)\n\n  // Deep link\n  actionUrl String? // \"/dashboard/contracts/clxyz123\"\n\n  createdAt DateTime @default(now())\n\n  // Relations\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@index([userId, read])\n  @@index([userId, createdAt(sort: Desc)])\n  @@map(\"notifications\")\n}\n",
    "runtimeDataModel": {
        "models": {},
        "enums": {},
        "types": {}
    },
    "parameterizationSchema": {
        "strings": [],
        "graph": ""
    }
};
